#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long id,val,max1,min1;
}a[100010];
long long n,m;
long long s[100010],tim[100010],now=1;
void clear()
{
    now++;
}
long long lowbit(long long x)
{
    return x&-x;
}
void update(long long x,long long v)
{
    for(long long i=x;i<=100000;i+=lowbit(i))
    {
        if(tim[i]!=now)
        {
            tim[i]=now;
            s[i]=0;
        }
        s[i]=max(s[i],v);
    }
}
long long query(long long x)
{
    long long ans=0;
    for(long long i=x;i>=1;i-=lowbit(i))
    {
        if(tim[i]!=now)
        {
            tim[i]=now;
            s[i]=0;
        }
        ans=max(ans,s[i]);
    }
    return ans;
}
bool cmpid(node a,node b)
{
    return a.id<b.id;
}
bool cmpval(node a,node b)
{
    return a.val<b.val;
}
bool cmpmax(node a,node b)
{
    return a.max1<b.max1;
}
long long ans,f[100010];
void cdq(long long l,long long r)
{
    if(l>=r)
    {
        return;
    }
    long long mid=(l+r)>>1;
    cdq(l,mid);
    sort(a+l,a+mid+1,cmpmax);
    sort(a+mid+1,a+r+1,cmpval);
    clear();
    for(long long i=l,j=mid+1;j<=r;j++)
    {
        while(i<=mid&&a[i].max1<=a[j].val)
        {
            update(a[i].val,f[a[i].id]);
            i++;
        }
        f[a[j].id]=max(f[a[j].id],query(a[j].min1)+1);
    }
    sort(a+l,a+mid+1,cmpid);
    sort(a+mid+1,a+r+1,cmpid);
    cdq(mid+1,r);
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        a[i].id=i;
        f[i]=1;
        scanf("%lld",&a[i].val);
        a[i].max1=a[i].min1=a[i].val;
    }
    for(long long i=1;i<=m;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        a[x].max1=max(a[x].max1,y);
        a[x].min1=min(a[x].min1,y);
    }
    cdq(1,n);
    for(long long i=1;i<=n;i++)
    {
        ans=max(ans,f[i]);
    }
    printf("%lld",ans);
    return 0;
}
